import heapq

class Solution(object):
    def minimizeStringValue(self, s):
        # Count existing character frequencies
        freq = [0] * 26
        for c in s:
            if c != '?':
                freq[ord(c) - ord('a')] += 1

        # Use min-heap to greedily pick the least frequent character for each '?'
        heap = [(freq[i], i) for i in range(26)]
        heapq.heapify(heap)

        chosen = []  # characters chosen for '?' positions
        q_count = s.count('?')
        for _ in range(q_count):
            cnt, idx = heapq.heappop(heap)
            chosen.append(chr(ord('a') + idx))
            heapq.heappush(heap, (cnt + 1, idx))

        # Sort chosen letters for lexicographic minimality when placing at '?' positions
        chosen.sort()

        result = list(s)
        ci = 0
        for i in range(len(result)):
            if result[i] == '?':
                result[i] = chosen[ci]
                ci += 1

        return ''.join(result)
